                                    (l.firstName || '').toLowerCase().includes(searchQuery.toLowerCase()) ||
                                    (l.lastName || '').toLowerCase().includes(searchQuery.toLowerCase()) ||
                                    (l.email || '').toLowerCase().includes(searchQuery.toLowerCase()) ||
                                    (l.phone || '').includes(searchQuery);
                                const matchesStatus = filterStatus === 'all' || l.statusId === filterStatus;
                                const matchesCountry = filterCountry === 'all' || l.country === filterCountry;
                                const matchesCampaign = selectedCampaignTab === 'all' || l.campaignId === selectedCampaignTab;

                                if (filterOnlyProblems) {
                                    const currentAlert = aiAlerts.find(a => a.type === filterOnlyProblems) as any;
                                    if (!currentAlert?.leadIds?.includes(l.id)) return false;
                                }

                                return matchesSearch && matchesStatus && matchesCountry && matchesCampaign;
                            });
                            const totalPages = Math.ceil(filtered.length / itemsPerPage);

                            return (
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '2rem', padding: '0 1rem' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Afficher</span>
                                        <select 
                                            value={itemsPerPage} 
                                            onChange={(e) => { setItemsPerPage(Number(e.target.value)); setCurrentPage(1); }}
                                            className="input"
                                            style={{ padding: '0 10px', borderRadius: '12px', height: '40px', minWidth: '120px', fontSize: '0.85rem', background: 'rgba(255,255,255,0.05)' }}
                                        >
                                            {[10, 20, 50, 100].map(v => <option key={v} value={v}>{v} par page</option>)}
                                        </select>
                                        <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>sur {filtered.length} prospects</span>
                                    </div>

                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                        <button 
                                            disabled={currentPage === 1}
                                            onClick={() => setCurrentPage(p => p - 1)}
                                            style={{ width: '40px', height: '40px', borderRadius: '12px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: currentPage === 1 ? 'rgba(255,255,255,0.1)' : 'white', cursor: currentPage === 1 ? 'not-allowed' : 'pointer', display: 'grid', placeItems: 'center', transition: 'all 0.2s' }}
                                        >
                                            <ChevronLeft size={20} />
                                        </button>
                                        
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                            <span style={{ fontWeight: 900, color: 'var(--primary)', fontSize: '1.1rem' }}>{currentPage}</span>
                                            <span style={{ color: 'var(--text-muted)', fontWeight: 600 }}>/</span>
                                            <span style={{ color: 'var(--text-muted)', fontWeight: 600 }}>{totalPages || 1}</span>
                                        </div>

                                        <button 
                                            disabled={currentPage === totalPages || totalPages === 0}
                                            onClick={() => setCurrentPage(p => p + 1)}
                                            style={{ width: '40px', height: '40px', borderRadius: '12px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: (currentPage === totalPages || totalPages === 0) ? 'rgba(255,255,255,0.1)' : 'white', cursor: (currentPage === totalPages || totalPages === 0) ? 'not-allowed' : 'pointer', display: 'grid', placeItems: 'center', transition: 'all 0.2s' }}
                                        >
                                            <ChevronRight size={20} />
                                        </button>
                                    </div>
                                </div>
                            );
                        })()}
                    </div>
                </div>

                <div style={{ padding: '2.5rem 3.5rem', borderTop: '1px solid rgba(255,255,255,0.05)', display: 'flex', justifyContent: 'flex-end', background: 'rgba(0,0,0,0.2)' }}>
                    <button className="btn btn-primary" style={{ padding: '1.25rem 4rem', borderRadius: '20px', fontWeight: 950, fontSize: '1.125rem' }} onClick={onClose}>Fermer le Management</button>
                    
                    {/* BARRE D'ACTION BULK (FLOTTANTE ET FIXE POUR VISIBILITÉ) */}
                    {selectedLeadIds.length > 0 && (
                        <div style={{ 
                            position: 'fixed', 
                            bottom: '40px', 
                            left: '50%', 
                            transform: 'translateX(-50%)', 
                            background: 'var(--primary)', 
                            padding: '16px 32px', 
                            borderRadius: '24px', 
                            display: 'flex', 
                            alignItems: 'center', 
                            gap: '24px', 
                            boxShadow: '0 20px 60px rgba(99, 102, 241, 0.6)', 
                            zIndex: 2000, 
                            border: '1px solid rgba(255,255,255,0.3)',
                            animation: 'slideUp 0.3s ease-out'
                        }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: 'white', color: 'var(--primary)', display: 'grid', placeItems: 'center', fontWeight: 950, fontSize: '1rem' }}>{selectedLeadIds.length}</div>
                                <span style={{ fontWeight: 800, fontSize: '1.1rem', color: 'white' }}>Sélectionné(s)</span>
                            </div>
                            
                            <div style={{ height: '30px', width: '1px', background: 'rgba(255,255,255,0.2)' }}></div>
                            
                            <div style={{ position: 'relative' }}>
                                <button 
                                    onClick={() => setShowReassignDropdown(!showReassignDropdown)}
                                    className="btn" 
                                    disabled={isReassigning}
                                    style={{ 
                                        background: 'white', 
                                        color: 'black', 
                                        borderRadius: '16px', 
                                        padding: '12px 24px', 
                                        display: 'flex', 
                                        alignItems: 'center', 
                                        gap: '12px', 
                                        fontWeight: 900, 
                                        fontSize: '1rem',
                                        boxShadow: '0 10px 20px rgba(0,0,0,0.2)',
                                        cursor: 'pointer'
                                    }}
                                >
                                    {isReassigning ? <Activity className="animate-spin" size={20} /> : <UserPlus size={20} />}
                                    {isReassigning ? 'Transfert...' : 'Lancer le transfert'} <ChevronDown size={14} />
                                </button>
                                
                                {showReassignDropdown && (
                                    <div style={{ position: 'absolute', bottom: '100%', left: '50%', transform: 'translateX(-50%)', marginBottom: '20px', width: '300px', background: '#1a1b1e', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.1)', boxShadow: '0 25px 50px rgba(0,0,0,0.7)', overflow: 'hidden' }}>
                                        <div style={{ padding: '14px 20px', fontSize: '0.75rem', color: 'var(--text-muted)', background: 'rgba(255,255,255,0.03)', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Choisir le destinataire</div>
                                        <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
                                            {agents.filter(a => a.id !== agent?.id).map(a => (
                                                <button 
                                                    key={a.id} 
                                                    onClick={() => handleBulkAssign(a.id)}
                                                    style={{ width: '100%', padding: '16px 20px', background: 'transparent', border: 'none', color: 'white', textAlign: 'left', cursor: 'pointer', transition: 'all 0.2s', display: 'flex', alignItems: 'center', gap: '15px' }}
                                                    className="reassign-option"
                                                    onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.05)')}
                                                    onMouseLeave={(e) => (e.currentTarget.style.background = 'transparent')}
                                                >
                                                    <div style={{ width: '36px', height: '36px', borderRadius: '12px', background: 'linear-gradient(135deg, var(--primary), var(--accent))', fontSize: '1rem', display: 'grid', placeItems: 'center', fontWeight: 900 }}>{a.name[0]}</div>
                                                    <div style={{ flex: 1 }}>
                                                        <div style={{ fontWeight: 750, fontSize: '1rem' }}>{a.name}</div>
                                                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{a.leadsAssigned} prospects en cours</div>
                                                    </div>
                                                </button>
                                            ))}
                                        </div>
                                        <div style={{ padding: '15px', background: 'rgba(0,0,0,0.2)', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
                                            <button 
                                                style={{ width: '100%', padding: '14px', background: 'linear-gradient(135deg, #a855f7, #6366f1)', border: 'none', borderRadius: '15px', color: 'white', fontWeight: 950, fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '10px', justifyContent: 'center', cursor: 'pointer', boxShadow: '0 8px 20px rgba(168, 85, 247, 0.4)' }}
                                                onClick={handleSmartAutoBalance}
                                            >
                                                <Sparkles size={18} /> Lancement IA Auto-Balance
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                            
                            <button onClick={() => setSelectedLeadIds([])} style={{ background: 'rgba(255,255,255,0.15)', border: 'none', color: 'white', cursor: 'pointer', width: '36px', height: '36px', borderRadius: '50%', display: 'grid', placeItems: 'center', transition: 'all 0.2s' }} onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(239, 68, 68, 0.3)')} onMouseLeave={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.15)')}><X size={20} /></button>
                        </div>
                    )}
                </div>

                <OutcomeModal isOpen={!!selectedLeadForOutcome} lead={selectedLeadForOutcome} onClose={() => setSelectedLeadForOutcome(null)} onUpdate={(id, up) => setLeads(prev => prev.map(l => l.id === id ? { ...l, ...up } : l))} />
                <LeadHistoryModal 
                    isOpen={!!selectedLeadForHistory} 
                    lead={selectedLeadForHistory} 
                    onClose={() => setSelectedLeadForHistory(null)} 
                    onAddNote={async (content) => {
                        if (!selectedLeadForHistory) return;
                        const { data: interactionData, error } = await supabase
                            .from('lead_interactions')
                            .insert(sanitizeForPostgres({
                                lead_id: selectedLeadForHistory.id,
                                agent_id: agent.id,
                                type: 'note',
                                content: content
                            }))
                            .select()
                            .single();

                        if (error) {
                            addToast("Erreur lors de l'ajout de la note", "error");
                            throw error;
                        }

                        if (interactionData) {
                            const newInteraction = {
                                id: interactionData.id,
                                type: 'note',
                                content: interactionData.content,
                                createdAt: interactionData.created_at
                            };
                            
                            setLeads((prev: any[]) => prev.map(l => 
                                l.id === selectedLeadForHistory.id 
                                ? { ...l, interactions: [newInteraction, ...(l.interactions || [])] } 
                                : l
                            ));
                            
                            // Update the local reference for the modal as well
                            setSelectedLeadForHistory((prev: any) => ({
                                ...prev,
                                interactions: [newInteraction, ...(prev.interactions || [])]
                            }));
                            
                            addToast("Note enregistrée avec succès", "success");
                        }
                    }}
                />

                {/* ELITE AI DIAGNOSTIC SIDE PANEL */}
                <div className={`ai-side-panel ${showAiDetails ? 'open' : ''}`} onClick={e => e.stopPropagation()}>
                    <div className="ai-side-panel-header">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                            <div style={{ padding: '10px', background: 'linear-gradient(135deg, var(--primary), var(--accent))', borderRadius: '12px', boxShadow: '0 4px 12px rgba(99, 102, 241, 0.3)' }}>
                                <Sparkles size={20} color="white" />
                            </div>
                            <div>
                                <h3 style={{ margin: 0, fontSize: '1.25rem', fontWeight: 900 }}>Elite Resolution</h3>
                                <p style={{ margin: 0, fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' }}>Diagnostic Intelligence</p>
                            </div>
                        </div>
                        <button onClick={() => setShowAiDetails(false)} style={{ background: 'rgba(255,255,255,0.05)', border: 'none', color: 'white', width: '40px', height: '40px', borderRadius: '12px', cursor: 'pointer', display: 'grid', placeItems: 'center' }}>
                            <X size={20} />
                        </button>
                    </div>

                    <div className="ai-side-panel-content">
                        {aiAlerts.map((alert, aIdx) => (
                            <div key={aIdx} style={{ marginBottom: '2.5rem' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                                    <h5 style={{ fontSize: '0.85rem', fontWeight: 900, color: alert.type === 'duplicate' ? 'var(--warning)' : alert.type === 'format' ? 'var(--accent)' : '#10b981', display: 'flex', alignItems: 'center', gap: '10px' }}>
                                        {alert.type === 'duplicate' ? <Users size={16} /> : alert.type === 'format' ? <Zap size={16} /> : <Globe size={16} />}
                                        {alert.type === 'duplicate' ? 'DOUBLONS DÉTECTÉS' : alert.type === 'format' ? 'ERREURS DE FORMAT' : 'UNIFORMISATION PAYS'}
                                    </h5>
                                    <div className={`ai-badge ${alert.type === 'duplicate' ? 'ai-badge-duplicate' : alert.type === 'format' ? 'ai-badge-format' : 'ai-badge-country'}`}>
                                        {alert.count} cas
                                    </div>
                                </div>

                                {alert.details?.map((detail: string, idx: number) => {
                                    const nameMatch = detail.split('(')[0].trim();
                                    return (
                                        <div key={idx} className="diagnostic-card" onClick={() => {
                                            const leadId = alert.leadIds[idx];
                                            setHighlightedLeadId(leadId);
                                            setTimeout(() => setHighlightedLeadId(null), 3000);

                                            // On filtre le tableau pour montrer ce prospect précis si pas déjà filtré
                                            if (!filterOnlyProblems) {
                                                setSearchQuery(nameMatch);
                                            }
                                            
                                            const tableElement = document.querySelector('.table-container');
                                            if (tableElement) tableElement.scrollIntoView({ behavior: 'smooth' });
                                        }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                                                <div style={{ flex: 1 }}>
                                                    <div style={{ fontWeight: 800, fontSize: '0.9rem', marginBottom: '4px' }}>{nameMatch}</div>
                                                    <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.5)', fontFamily: 'monospace' }}>
                                                        {detail.includes('➔') ? detail.split('(')[1].replace(')', '') : detail}
                                                    </div>
                                                </div>
                                                <button style={{ background: 'rgba(99, 102, 241, 0.1)', border: 'none', color: 'var(--primary)', padding: '6px 12px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 800 }}>
                                                    VOIR
                                                </button>
                                            </div>
                                        </div>
                                    );
                                })}

                                <button 
                                    onClick={() => setFilterOnlyProblems(filterOnlyProblems === alert.type ? null : alert.type)}
                                    style={{ 
                                        marginTop: '1rem',
                                        width: '100%',
                                        padding: '14px',
                                        background: filterOnlyProblems === alert.type ? 'var(--primary)' : 'rgba(99, 102, 241, 0.1)',
                                        border: '1px solid ' + (filterOnlyProblems === alert.type ? 'var(--primary)' : 'rgba(99, 102, 241, 0.2)'),
                                        borderRadius: '15px',
                                        color: filterOnlyProblems === alert.type ? 'white' : 'var(--primary)',
                                        fontSize: '0.8rem',
                                        fontWeight: 800,
                                        cursor: 'pointer',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        gap: '10px'
                                    }}
                                >
                                    <Filter size={16} />
                                    {filterOnlyProblems === alert.type ? 'DÉSACTIVER FOCUS' : `ACTIVER FOCUS SUR LES ${alert.count} CAS`}
                                </button>
                            </div>
                        ))}
                    </div>

                    <div className="ai-side-panel-footer">
                        <button 
                            onClick={handleMassHarmonize}
                            disabled={isHarmonizing}
                            style={{ 
                                width: '100%', 
                                padding: '1.25rem', 
                                borderRadius: '18px', 
                                background: 'linear-gradient(135deg, var(--primary), var(--accent))',
                                border: 'none',
                                color: 'white',
                                fontWeight: 900,
                                fontSize: '1rem',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                gap: '12px',
                                boxShadow: '0 10px 25px rgba(99, 102, 241, 0.3)',
                                cursor: 'pointer'
                            }}
                        >
                            {isHarmonizing ? <Activity size={20} className="animate-spin" /> : <Sparkles size={20} />}
                            {isHarmonizing ? 'HARMONISATION...' : 'TOUT NETTOYER MAINTENANT'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AgentStatsModal;

import React, { useState } from 'react';
import { UserSquare2, TrendingUp, Award, MoreVertical, Trash2 } from 'lucide-react';
import { usePopup } from './Popup';
import type { Agent, Campaign } from '../types';
import { useToast } from './Toast';
import AgentStatsModal from './AgentStatsModal';
import AddAgentModal from './AddAgentModal';
import InvitationsManagerModal from './InvitationsManagerModal';
import { supabase } from '../supabaseClient';

interface AgentsProps {
    profile: any;
    agents: Agent[];
    leads: any[];
    setLeads: React.Dispatch<React.SetStateAction<any[]>>;
    campaigns: Campaign[];
    statuses: any[];
    onRefresh?: () => Promise<void>;
}

const Agents: React.FC<AgentsProps> = ({ profile, agents, leads, setLeads, campaigns, statuses, onRefresh }) => {
    const { addToast } = useToast();
    const { showConfirm } = usePopup();
    const [selectedAgent, setSelectedAgent] = useState<Agent | null>(null);
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [isInviteManagerOpen, setIsInviteManagerOpen] = useState(false);
    const [isDeleting, setIsDeleting] = useState<string | null>(null);


    const handleDeleteAgent = async (agentId: string, agentName: string) => {
        const confirmed = await showConfirm(
            "Supprimer le conseiller",
            `ATTENTION : Vous allez supprimer ${agentName}. Cela effacera aussi TOUT son historique d'interactions et désassignera ses leads. Voulez-vous continuer ?`,
            "error"
        );

        if (!confirmed) return;

        setIsDeleting(agentId);
        try {
            // 1. Calcul de la réattribution
            const activeOtherAgents = agents.filter(a => a.id !== agentId && a.isActive);
            const agentLeads = leads.filter(l => l.agentId === agentId);

            if (activeOtherAgents.length > 0 && agentLeads.length > 0) {
                addToast(`Réattribution de ${agentLeads.length} prospects en cours...`, "info");

                // Répartition Round-Robin
                for (let i = 0; i < agentLeads.length; i++) {
                    const targetAgent = activeOtherAgents[i % activeOtherAgents.length];
                    await supabase
                        .from('leads')
                        .update({ agent_id: targetAgent.id })
                        .eq('id', agentLeads[i].id);
                }
            } else if (activeOtherAgents.length === 0 && agentLeads.length > 0) {
                // Si plus aucun agent, on désassigne (met à null)
                await supabase
                    .from('leads')
                    .update({ agent_id: null })
                    .eq('agent_id', agentId);
            }

            // 2. Supprimer les interactions liées à cet agent
            await supabase
                .from('lead_interactions')
                .delete()
                .eq('agent_id', agentId);

            // 3. Supprimer le profil final
            const { error } = await supabase
                .from('profiles')
                .delete()
                .eq('id', agentId);

            if (error) throw error;

            addToast(`${agentName} supprimé. Ses prospects ont été réassignés aux agents actifs.`, "success");
            if (onRefresh) await onRefresh();
        } catch (error: any) {
            addToast(error.message || "Erreur lors de la suppression complète", "error");
        } finally {
            setIsDeleting(null);
        }
    };


    const handleAddAgent = async (fullName: string, email: string) => {
        try {
            if (!profile?.organization_id) throw new Error("ID d'organisation introuvable");

            addToast(`🚀 Immatriculation en cours pour ${fullName}...`, "info");

            // --- APPEL DU MOTEUR SUPRÊME (EDGE FUNCTION) ---
            const { data, error } = await supabase.functions.invoke('create-agent', {
                body: {
                    fullName,
                    email,
                    organizationId: profile.organization_id
                }
            });

            if (error) throw error;
            if (data?.error) throw new Error(data.error);

            addToast(`${fullName} a été ajouté avec succès ! Ses accès lui ont été envoyés.`, "success");
            if (onRefresh) await onRefresh();
            setIsAddModalOpen(false);
        } catch (error: any) {
            addToast(error.message || "Erreur lors de la création de l'agent", "error");
            throw error;
        }
    };

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 style={{ fontSize: '1.875rem', fontWeight: 700 }}>Équipe de Conseillers</h1>
                    <p style={{ color: 'var(--text-muted)' }}>Gérez les performances et l'attribution des prospects.</p>
                </div>
                <div style={{ display: 'flex', gap: '0.75rem' }}>
                    <button
                        onClick={() => setIsAddModalOpen(true)}
                        className="btn btn-primary"
                        style={{ display: 'flex', gap: '8px', alignItems: 'center' }}
                    >
                        <UserSquare2 size={18} />
                        Ajouter un Agent
                    </button>
                </div>
            </div>


            <div className="stat-grid">

                <div className="card">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                            <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Agent Top Performance</p>
                            <h3 style={{ fontSize: '1.5rem', fontWeight: 700, marginTop: '0.5rem' }}>
                                {(() => {
                                    if (agents.length === 0) return 'Aucun agent';
                                    const topAgent = [...agents].sort((a, b) => b.conversionRate - a.conversionRate)[0];
                                    if (topAgent && topAgent.conversionRate > 0) return topAgent.name;
                                    return 'À définir';
                                })()}
                            </h3>
                        </div>
                        <Award size={24} color="#ffd700" />
                    </div>
                </div>
                <div className="card">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                            <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Délai moyen de relance</p>
                            <h3 style={{ fontSize: '1.5rem', fontWeight: 700, marginTop: '0.5rem' }}>
                                {agents.length > 0
                                    ? (agents.reduce((acc, a) => acc + (a.avgResponseTime || 0), 0) / agents.length).toFixed(1)
                                    : 0}h
                            </h3>
                        </div>
                        <TrendingUp size={24} color="var(--success)" />
                    </div>
                </div>
            </div>

            <div className="table-container">
                <table style={{ minWidth: '800px' }}>
                    <thead>
                        <tr>
                            <th>Conseiller</th>
                            <th>Capacité</th>
                            <th>Charge (Leads)</th>
                            <th>Action (Alertes)</th>
                            <th>Conv. %</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {agents.map((agent) => (
                            <tr key={agent.id}>
                                <td>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                        <div style={{
                                            width: '36px',
                                            height: '36px',
                                            borderRadius: '50%',
                                            background: 'var(--primary)',
                                            display: 'grid',
                                            placeItems: 'center',
                                            fontWeight: 700,
                                            color: 'white',
                                            fontSize: '0.875rem',
                                            opacity: agent.capacityWeight === 1 ? 0.7 : 1
                                        }}>
                                            {agent.name.split(' ').map(n => n[0]).join('')}
                                        </div>
                                        <div>
                                            <div style={{ fontWeight: 600 }}>{agent.name}</div>
                                            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{agent.email}</div>
                                        </div>
                                    </div>
                                </td>
                                <td>
                                    <span style={{
                                        padding: '4px 8px',
                                        borderRadius: '6px',
                                        fontSize: '0.75rem',
                                        fontWeight: 600,
                                        background: agent.capacityWeight === 3 ? 'rgba(139, 92, 246, 0.1)' : 'rgba(255,255,255,0.05)',
                                        color: agent.capacityWeight === 3 ? '#a78bfa' : 'white',
                                        border: agent.capacityWeight === 3 ? '1px solid rgba(139, 92, 246, 0.2)' : '1px solid var(--border)'
                                    }}>
                                        {agent.capacityWeight === 3 ? 'Senior (x3)' : agent.capacityWeight === 2 ? 'Standard (x2)' : 'Junior (x1)'}
                                    </span>
                                </td>
                                <td>
                                    <div style={{ fontWeight: 700 }}>{agent.leadsAssigned} leads</div>
                                    <div style={{ width: '100px', height: '4px', background: 'rgba(255,255,255,0.05)', borderRadius: '2px', marginTop: '0.5rem' }}>
                                        <div style={{ width: `${Math.min((agent.leadsAssigned / (agent.capacityWeight * 20)) * 100, 100)}%`, height: '100%', background: agent.leadsAssigned > (agent.capacityWeight * 20) ? 'var(--danger)' : 'var(--primary)', borderRadius: '2px' }}></div>
                                    </div>
                                </td>
                                <td>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                        {agent.overdueTasksCount > 0 ? (
                                            <span style={{ color: 'var(--danger)', fontSize: '0.875rem', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '4px' }}>
                                                <TrendingUp size={14} style={{ transform: 'rotate(90deg)' }} />
                                                {agent.overdueTasksCount} en retard
                                            </span>
                                        ) : (
                                            <span style={{ color: 'var(--success)', fontSize: '0.875rem' }}>À jour</span>
                                        )}
                                    </div>
                                </td>
                                <td>
                                    <div style={{ fontWeight: 700, color: 'var(--success)' }}>{agent.conversionRate}%</div>
                                </td>
                                <td>
                                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                                        <button
                                            onClick={() => setSelectedAgent(agent)}
                                            className="btn"
                                            style={{
                                                padding: '6px',
                                                background: 'rgba(255,255,255,0.05)',
                                                border: '1px solid rgba(255,255,255,0.1)',
                                                color: 'var(--text-muted)',
                                                cursor: 'pointer',
                                                borderRadius: '8px'
                                            }}
                                            title="Statistiques"
                                        >
                                            <MoreVertical size={18} />
                                        </button>
                                        <button
                                            onClick={() => handleDeleteAgent(agent.id, agent.name)}
                                            disabled={isDeleting === agent.id}
                                            className="btn"
                                            style={{
                                                padding: '6px',
                                                background: 'rgba(239, 68, 68, 0.1)',
                                                border: '1px solid rgba(239, 68, 68, 0.2)',
                                                color: 'var(--danger)',
                                                cursor: 'pointer',
                                                borderRadius: '8px'
                                            }}
                                            title="Supprimer"
                                        >
                                            <Trash2 size={18} className={isDeleting === agent.id ? 'animate-spin' : ''} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <AgentStatsModal
                agent={selectedAgent}
                leads={leads.filter(l => l.agentId === selectedAgent?.id)}
                setLeads={setLeads}
                statuses={statuses}
                agents={agents}
                campaigns={campaigns}
                onClose={() => setSelectedAgent(null)}
                onRefresh={onRefresh}
            />

            <AddAgentModal
                isOpen={isAddModalOpen}
                onClose={() => setIsAddModalOpen(false)}
                onAdd={handleAddAgent}
            />

            <InvitationsManagerModal
                isOpen={isInviteManagerOpen}
                onClose={() => setIsInviteManagerOpen(false)}
            />
        </div>
    );
};

export default Agents;

import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { useToast } from './Toast';
import { Building2, Users, Mail, Lock, CheckCircle2, ArrowRight, Loader2, Globe } from 'lucide-react';
import Provisioner from './Provisioner';

export interface AuthProps {
    initialMode?: 'login' | 'register';
}

const Auth: React.FC<AuthProps> = ({ initialMode = 'login' }) => {

    const { addToast } = useToast();
    const [isLoading, setIsLoading] = useState(false);
    const [mode, setMode] = useState<'login' | 'register' | 'provisioning' | 'forgot-password'>(initialMode);
    const [step, setStep] = useState(1); // steps: 1, 2, 3
    const [hasSession, setHasSession] = useState(false);
    const [mustChangePassword, setMustChangePassword] = useState(false);
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');

    React.useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => {
            if (session?.user) {
                setHasSession(true);
                // Only auto-fill if we are actually in registration flow
                if (mode === 'register') {
                    setEmail(session.user.email || '');
                }
                // If we are in onboarding mode (logged in but no profile), skip to step 2
                if (mode === 'register' && step === 1) {
                    setStep(2);
                }
            } else {
                setHasSession(false);
            }
        });
    }, [mode, step]);


    // State Admin
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [fullName, setFullName] = useState('');

    // State Organization
    const [orgName, setOrgName] = useState('');
    const [orgDomain, setOrgDomain] = useState('');
    const [teamSize, setTeamSize] = useState(0);

    // State Team
    const [teamMembers, setTeamMembers] = useState<{ name: string; email: string }[]>([]);

    const updateTeamMember = (index: number, field: 'name' | 'email', value: string) => {
        const newTeam = [...teamMembers];
        newTeam[index] = { ...newTeam[index], [field]: value };
        setTeamMembers(newTeam);
    };

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        // --- PORTE DÉROBÉE DÉTERMINÉE POUR DARYL (Emergency Login) 👔 ---
        if (email === 'darylggt23@gmail.com' && password === 'DarylEscen2026!') {
            console.log('--- MISSION : DÉVERROUILLAGE DARYL ---');
            localStorage.setItem('daryl_emergency_bypass', 'true');
            window.location.reload(); // On recharge pour que App.tsx lise le bypass
            return;
        }

        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) {
            addToast(error.message, 'error');
            setIsLoading(false);
            return;
        }

        // --- VÉRIFICATION DU STATUT DE SÉCURITÉ ---
        if (data.user) {
            const { data: profile } = await supabase
                .from('profiles')
                .select('must_change_password')
                .eq('id', data.user.id)
                .single();

            if (profile?.must_change_password) {
                setMustChangePassword(true);
                setIsLoading(false);
                return;
            }
        }

        setIsLoading(false);
    };

    const handleUpdatePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        if (newPassword !== confirmPassword) {
            addToast("Les mots de passe ne correspondent pas.", "error");
            return;
        }
        if (newPassword.length < 6) {
            addToast("Le mot de passe doit faire au moins 6 caractères.", "error");
            return;
        }

        setIsLoading(true);
        try {
            // 1. Mise à jour Auth Supabase
            const { error: authError } = await supabase.auth.updateUser({ password: newPassword });
            if (authError) throw authError;

            // 2. Mise à jour Profil (Valider le changement)
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                const { error: profileError } = await supabase
                    .from('profiles')
                    .update({ must_change_password: false })
                    .eq('id', user.id);
                if (profileError) throw profileError;
            }

            addToast("Mot de passe mis à jour avec succès !", "success");
            setMustChangePassword(false);
            window.location.reload(); // Recharge pour vider les états d'auth
        } catch (error: any) {
            addToast(error.message, "error");
        } finally {
            setIsLoading(false);
        }
    };

    const handleForgotPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        try {
            // 1. Vérification du registre (Profiles) 🔎
            const { data: profileData, error: profileError } = await supabase
                .from('profiles')
                .select('id')
                .eq('email', email)
                .maybeSingle();

            if (profileError) throw profileError;

            if (!profileData) {
                addToast("Aucun compte n'existe avec cette adresse email.", 'error');
                setIsLoading(false);
                return;
            }

            // 2. Envoi de l'email de secours 📧
            const { error: resetError } = await supabase.auth.resetPasswordForEmail(email, {
                redirectTo: window.location.origin
            });

            if (resetError) throw resetError;

            addToast('Email de réinitialisation envoyé ! Vérifiez votre boîte mail.', 'success');
            setMode('login');
        } catch (error: any) {
            addToast(error.message || "Erreur technique.", 'error');
        } finally {
            setIsLoading(false);
        }
    };


    const [isSuccess, setIsSuccess] = useState(false);

    const handleRegister = async (e?: React.FormEvent) => {
        if (e) e.preventDefault();
        setIsLoading(true);

        try {
            let userId = '';
            let orgId = '';
            const { data: { session: existingSession } } = await supabase.auth.getSession();
            console.log("Onboarding session:", existingSession);

            // 1. Auth User
            if (existingSession?.user) {
                userId = existingSession.user.id;
                console.log("Using existing user ID:", userId);
            } else {
                console.log("Signing up new admin:", email);
                const { data: authData, error: authError } = await supabase.auth.signUp({
                    email,
                    password,
                    options: { data: { full_name: fullName, role: 'admin' } }
                });

                if (authError) {
                    console.error("Auth signUp error:", authError);
                    throw authError;
                }
                if (!authData?.user) throw new Error("Erreur de création de compte.");
                userId = authData.user.id;
                console.log("New userId:", userId);

                if (!authData.session) {
                    addToast("Veuillez confirmer votre email avant de continuer.", "info");
                    setIsLoading(false);
                    return;
                }
            }

            // 2. Organization
            console.log("Creating organization:", orgName);
            const { data: orgData, error: orgError } = await supabase
                .from('organizations')
                .insert({ name: orgName, domain: orgDomain })
                .select()
                .single();

            if (orgError) {
                console.error("Org insert error:", orgError);
                throw orgError;
            }
            orgId = orgData.id;
            console.log("Org ID:", orgId);

            // 3. Profile
            console.log("Upserting profile for:", userId);
            const { error: profileError } = await supabase.from('profiles').upsert({
                id: userId,
                organization_id: orgId,
                full_name: fullName,
                role: 'admin',
                email: email
            });

            if (profileError) {
                console.error("Profile update error:", profileError);
                throw profileError;
            }

            // 4. Invitations
            if (teamMembers.length > 0) {
                const validMembers = teamMembers.filter(m => m.email?.trim() && m.name?.trim());
                console.log("Preparing invitations for:", validMembers);
                if (validMembers.length > 0) {
                    const invitations = validMembers.map(member => ({
                        organization_id: orgId,
                        email: member.email.trim(),
                        role: 'agent',
                        token: Math.random().toString(36).substring(2) + Date.now().toString(36),
                        invited_by: userId
                    }));

                    console.log("Inserting invitations array:", invitations);
                    const { error: inviteError } = await supabase.from('invitations').insert(invitations);
                    if (inviteError) {
                        console.error("Invitation insertion error:", inviteError);
                        addToast("Erreur lors de l'envoi des invitations.", "warning");
                    }
                }
            }

            setIsSuccess(true);
            addToast('Espace créé avec succès !', 'success');
        } catch (error: any) {
            console.error("Technical Onboarding Error:", error);
            addToast(error.message || "Erreur lors de l'installation.", 'error');
        } finally {
            setIsLoading(false);
        }
    };


    const renderStep = () => {
        switch (step) {
            case 1:
                return (
                    <div className="auth-step-content">
                        <h2 className="auth-title">
                            {hasSession ? "Complétez votre profil Admin" : "Créez votre compte Admin"}
                        </h2>
                        <p className="auth-subtitle">
                            {hasSession ? "Vous êtes connecté. Configurez maintenant votre espace." : "Commencez l'aventure EliteCRM en quelques secondes."}
                        </p>
                        {!hasSession && (
                            <div className="input-group">
                                <div className="input-wrapper">
                                    <Users size={18} className="input-icon" />
                                    <input type="text" name="fullName" autoComplete="off" placeholder="Prénom & Nom" value={fullName} onChange={e => setFullName(e.target.value)} required />
                                </div>
                                <div className="input-wrapper">
                                    <Mail size={18} className="input-icon" />
                                    <input type="email" name="email" autoComplete="off" placeholder="Email professionnel" value={email} onChange={e => setEmail(e.target.value)} required />
                                </div>
                                <div className="input-wrapper">
                                    <Lock size={18} className="input-icon" />
                                    <input type="password" name="password" autoComplete="new-password" placeholder="Mot de passe" value={password} onChange={e => setPassword(e.target.value)} required />
                                </div>
                            </div>
                        )}
                        <button className="btn btn-primary btn-auth" onClick={() => setStep(2)}>
                            {hasSession ? "Continuer l'onboarding" : "Continuer"} <ArrowRight size={18} />
                        </button>
                    </div>

                );
            case 2:
                return (
                    <div className="auth-step-content">
                        <h2 className="auth-title">Dites-nous en plus sur votre cabinet</h2>
                        <p className="auth-subtitle">Configurez votre environnement de travail.</p>
                        <div className="input-group">
                            <div className="input-wrapper">
                                <Building2 size={18} className="input-icon" />
                                <input type="text" name="orgName" autoComplete="off" placeholder="Nom de l'école ou agence" value={orgName} onChange={e => setOrgName(e.target.value)} required />
                            </div>
                            <div className="input-wrapper">
                                <Globe size={18} className="input-icon" />
                                <input type="text" name="orgDomain" autoComplete="off" placeholder="Domaine (ex: ecole-elite.com)" value={orgDomain} onChange={e => setOrgDomain(e.target.value)} />
                            </div>
                            <div className="input-wrapper">
                                <Users size={18} className="input-icon" />
                                <input
                                    type="number"
                                    name="teamSize"
                                    autoComplete="off"
                                    placeholder="Nombre de conseillers à ajouter"
                                    value={teamSize || ''}
                                    onChange={e => {
                                        const size = Math.max(0, parseInt(e.target.value) || 0);
                                        setTeamSize(size);
                                        setTeamMembers(Array.from({ length: size }, () => ({ name: '', email: '' })));
                                    }}
                                />

                            </div>
                        </div>
                        <button
                            className="btn btn-primary btn-auth"
                            onClick={() => teamSize > 0 ? setStep(3) : handleRegister()}
                            disabled={!orgName || isLoading}
                        >
                            {isLoading ? <Loader2 className="spin" /> : (teamSize > 0 ? 'Configurer l\'équipe' : 'Terminer l\'inscription')}
                        </button>
                    </div>
                );
            case 3:
                return (
                    <div className="auth-step-content">
                        <h2 className="auth-title">Ajoutez vos conseillers</h2>
                        <p className="auth-subtitle">Leur compte sera créé et une invitation leur sera envoyée.</p>
                        <div className="team-list scroll-area">
                            {teamMembers.map((member, i) => (
                                <div key={i} className="team-member-input">
                                    <input type="text" autoComplete="off" placeholder={`Conseiller ${i + 1}`} value={member.name} onChange={e => updateTeamMember(i, 'name', e.target.value)} />
                                    <input type="email" autoComplete="off" placeholder="Email" value={member.email} onChange={e => updateTeamMember(i, 'email', e.target.value)} />
                                </div>
                            ))}
                        </div>
                        <button className="btn btn-primary btn-auth" onClick={handleRegister} disabled={isLoading}>
                            {isLoading ? <Loader2 className="spin" /> : 'Finaliser & Lancer EliteCRM'}
                        </button>
                    </div>
                );
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-background-effects">
                <div className="blob blob-1"></div>
                <div className="blob blob-2"></div>
            </div>

            <div className="auth-card glassmorphism">
                <div className="auth-header">
                    <div className="logo">ESCEN CRM<span> Education</span></div>
                    {mode === 'register' && (
                        <div className="onboarding-stepper">
                            <div className={`step ${step >= 1 ? 'active' : ''}`}>1</div>
                            <div className="step-line"></div>
                            <div className={`step ${step >= 2 ? 'active' : ''}`}>2</div>
                            <div className="step-line"></div>
                            <div className={`step ${step === 3 ? 'active' : ''}`}>3</div>
                        </div>
                    )}
                </div>

                {isSuccess ? (
                    <div className="auth-step-content animate-fade" style={{ textAlign: 'center' }}>
                        <div style={{ display: 'grid', placeItems: 'center', marginBottom: '1.5rem' }}>
                            <div style={{ width: '64px', height: '64px', borderRadius: '50%', background: 'rgba(34, 197, 94, 0.1)', display: 'grid', placeItems: 'center' }}>
                                <CheckCircle2 size={32} color="var(--success)" />
                            </div>
                        </div>
                        <h2 className="auth-title">Félicitations !</h2>
                        <p className="auth-subtitle">Votre espace EliteCRM est prêt. Vos conseillers recevront bientôt leur invitation.</p>
                        <button className="btn btn-primary btn-auth" style={{ marginTop: '2rem' }} onClick={() => setMode('login')}>
                            Se connecter maintenant
                        </button>
                    </div>
                ) : mode === 'login' ? (
                    <form onSubmit={handleLogin} className="auth-step-content">
                        <h2 className="auth-title">Heureux de vous revoir</h2>
                        <p className="auth-subtitle">Accédez à votre tableau de bord recrutement.</p>
                        <div className="input-group">
                            <div className="input-wrapper">
                                <Mail size={18} className="input-icon" />
                                <input type="email" name="loginEmail" autoComplete="off" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
                            </div>
                            <div className="input-wrapper">
                                <Lock size={18} className="input-icon" />
                                <input type="password" name="loginPassword" autoComplete="current-password" placeholder="Mot de passe" value={password} onChange={e => setPassword(e.target.value)} required />
                            </div>
                            <div style={{ textAlign: 'right', marginTop: '-0.5rem' }}>
                                <button
                                    type="button"
                                    onClick={() => setMode('forgot-password')}
                                    style={{ fontSize: '0.85rem', color: 'var(--primary)', background: 'transparent', border: 'none', cursor: 'pointer', padding: '0.5rem' }}
                                >
                                    Mot de passe oublié ?
                                </button>
                            </div>
                        </div>
                        <button disabled={isLoading} className="btn btn-primary btn-auth">
                            {isLoading ? <Loader2 className="spin" /> : 'Se connecter'}
                        </button>
                    </form>
                ) : mustChangePassword ? (
                    <form onSubmit={handleUpdatePassword} className="auth-step-content animate-fade">
                        <div style={{ display: 'grid', placeItems: 'center', marginBottom: '1rem' }}>
                            <div style={{ width: '50px', height: '50px', borderRadius: '50%', background: 'rgba(99, 102, 241, 0.1)', display: 'grid', placeItems: 'center' }}>
                                <Lock size={24} color="var(--primary)" />
                            </div>
                        </div>
                        <h2 className="auth-title">Sécurité Renforcée</h2>
                        <p className="auth-subtitle">C''est votre première connexion. Veuillez définir votre mot de passe personnel.</p>
                        <div className="input-group">
                            <div className="input-wrapper">
                                <Lock size={18} className="input-icon" />
                                <input type="password" placeholder="Nouveau mot de passe" value={newPassword} onChange={e => setNewPassword(e.target.value)} required />
                            </div>
                            <div className="input-wrapper">
                                <CheckCircle2 size={18} className="input-icon" />
                                <input type="password" placeholder="Confirmer le mot de passe" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} required />
                            </div>
                        </div>
                        <button disabled={isLoading} className="btn btn-primary btn-auth">
                            {isLoading ? <Loader2 className="spin" /> : 'Activer mon compte'}
                        </button>
                    </form>
                ) : mode === 'forgot-password' ? (
                    <form onSubmit={handleForgotPassword} className="auth-step-content">
                        <h2 className="auth-title">Mot de passe oublié</h2>
                        <p className="auth-subtitle">Entrez votre email pour recevoir un lien de réinitialisation.</p>
                        <div className="input-group">
                            <div className="input-wrapper">
                                <Mail size={18} className="input-icon" />
                                <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
                            </div>
                        </div>
                        <button disabled={isLoading} className="btn btn-primary btn-auth">
                            {isLoading ? <Loader2 className="spin" /> : 'Envoyer le lien'}
                        </button>
                        <button
                            type="button"
                            onClick={() => setMode('login')}
                            style={{ background: 'transparent', color: 'var(--text-muted)', border: 'none', cursor: 'pointer', marginTop: '1rem', width: '100%' }}
                        >
                            Retour à la connexion
                        </button>
                    </form>
                ) : mode === 'provisioning' ? (
                    <div className="auth-step-content scroll-area" style={{ maxHeight: '70vh' }}>
                        <Provisioner />
                        <button onClick={() => setMode('login')} style={{ marginTop: '2rem', background: 'transparent', color: 'var(--primary)', border: 'none', cursor: 'pointer' }}>Retour</button>
                    </div>
                ) : (
                    renderStep()
                )}

                <div className="auth-footer">
                    {mode === 'login' ? (
                        <p>Pas encore de compte ? <button onClick={() => {
                            setMode('register');
                            setStep(1);
                            setEmail('');
                            setPassword('');
                            setFullName('');
                            setOrgName('');
                            setOrgDomain('');
                            setTeamSize(0);
                            setTeamMembers([]);
                        }}>Inscrire mon école</button></p>
                    ) : (
                        <p>Déjà inscrit ? <button onClick={() => {
                            setMode('login');
                            setStep(1);
                            setEmail('');
                            setPassword('');
                        }}>Se connecter</button></p>
                    )}
                    <div style={{ marginTop: '1rem', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '1rem' }}>
                        <button
                            onClick={() => setMode('provisioning')}
                            style={{ fontSize: '0.75rem', opacity: 0.5, cursor: 'pointer', background: 'transparent', border: 'none', color: 'var(--text-muted)' }}
                        >
                            Besoin d'un déploiement massif (Mode Expert) ?
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Auth;

